module pulse_gen(
    input clk,
    input trigger,
    output reg pulse
);

    reg trigger_prev = 0;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (trigger && !trigger_prev) begin
            pulse <= 1;
        end else begin
            pulse <= 0;
        end
        trigger_prev <= trigger;
    end

endmodule
